import java.util.*;
class Solution {
  static boolean solve(String s) {
    Deque<Character> st = new ArrayDeque<>();
    Map<Character,Character> pairs = Map.of(')', '(', ']', '[', '}', '{');
    for (int i=0;i<s.length();i++){
      char ch = s.charAt(i);
      if (ch=='('||ch=='['||ch=='{') st.push(ch);
      else if (ch==')'||ch==']'||ch=='}'){
        if (st.isEmpty() || st.pop() != pairs.get(ch)) return false;
      }
    }
    return st.isEmpty();
  }
}

