import java.util.*;
class Solution {
  static List<String> solve(String[] arr, int k) {
    Map<String,Integer> freq = new HashMap<>();
    for (String x : arr) freq.put(x, freq.getOrDefault(x,0)+1);
    List<Map.Entry<String,Integer>> list = new ArrayList<>(freq.entrySet());
    list.sort((a,b)->b.getValue()-a.getValue());
    List<String> out = new ArrayList<>();
    for (int i=0;i<Math.min(k, list.size());i++) out.add(list.get(i).getKey());
    return out;
  }
}

