// Caso: Validar RUT chileno | Nivel: Intermedio | Categoría: Validación
import java.util.*;

class Solution {
  static boolean solve(String rut) {
    String clean = rut == null ? "" : rut.replace(".", "").replace("-", "").replace(" ", "").toUpperCase();
    if (clean.length() < 2) return false;

    String body = clean.substring(0, clean.length() - 1);
    char dv = clean.charAt(clean.length() - 1);

    if (!body.chars().allMatch(Character::isDigit)) return false;

    int sum = 0;
    int mul = 2;
    for (int i = body.length() - 1; i >= 0; i--) {
      int d = body.charAt(i) - '0';
      sum += d * mul;
      mul = (mul == 7) ? 2 : (mul + 1);
    }

    int mod = 11 - (sum % 11);
    char dvCalc = (mod == 11) ? '0' : (mod == 10) ? 'K' : (char)('0' + mod);
    return dv == dvCalc;
  }
}

