import org.apache.poi.xssf.usermodel.*;
import org.apache.poi.ss.usermodel.*;

class Solution {
  static void solve() throws Exception {
    try (var wb = new XSSFWorkbook()) {
      var ws = wb.createSheet("Reporte");
      ws.createFreezePane(0,1);

      var bold = wb.createCellStyle();
      var font = wb.createFont(); font.setBold(true);
      bold.setFont(font);
      bold.setAlignment(HorizontalAlignment.CENTER);

      String[] headers = {"Nombre","Email","Puntos"};
      var r0 = ws.createRow(0);
      for (int i=0;i<headers.length;i++){
        var c = r0.createCell(i); c.setCellValue(headers[i]); c.setCellStyle(bold);
      }
      Object[][] rows = {
        {"Ana","ana@demo.cl",10},
        {"Beto","beto@demo.cl",7},
        {"Carla","carla@demo.cl",9},
      };
      var numStyle = wb.createCellStyle();
      numStyle.setDataFormat(wb.createDataFormat().getFormat("0"));

      for (int r=0;r<rows.length;r++){
        var row = ws.createRow(r+1);
        row.createCell(0).setCellValue((String)rows[r][0]);
        row.createCell(1).setCellValue((String)rows[r][1]);
        var c2 = row.createCell(2);
        c2.setCellValue(((Number)rows[r][2]).doubleValue());
        c2.setCellStyle(numStyle);
      }
      for (int i=0;i<3;i++) ws.autoSizeColumn(i);

      try (var out = new FileOutputStream("reporte_formato.xlsx")) {
        wb.write(out);
      }
    }
  }
}

